  /* ClockModule_LPCR: ??=0,??=0,??=0,??=0,LPD=0 */
  setReg8(ClockModule_LPCR, 0x00U);    /* Set the low power divider */ 
  /* RTCDR: RTCDF=0x00A8BFFF */
  setReg32(RTCDR, 0x00A8BFFFUL);       /* Set the RTC divider */ 
  /*** End of PE initialization code after reset ***/

